CREATE DATABASE IF NOT EXISTS sobatanak_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE sobatanak_db;
DROP TABLE IF EXISTS rewards;
DROP TABLE IF EXISTS testimonials;
DROP TABLE IF EXISTS articles;
DROP TABLE IF EXISTS products;
CREATE TABLE products (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255),category VARCHAR(255),price INT UNSIGNED,badge VARCHAR(255) NULL,rating DECIMAL(2,1),sold INT UNSIGNED,image TEXT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE articles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,title VARCHAR(255),excerpt TEXT,category VARCHAR(255),image TEXT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE testimonials (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255),message TEXT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE rewards (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255),points INT UNSIGNED,description TEXT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
